"use client";

import React from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { Icon } from "@/components/ui/Icon";

interface SidebarProps {
  active?: string;
  counts?: Record<string, number | undefined>;
}

export function Sidebar({ active, counts = {} }: SidebarProps) {
  const pathname = usePathname();

  function isActive(id: string, href: string): boolean {
    if (active) return active === id;
    return pathname === href || pathname.startsWith(href + "/");
  }

  const items = [
    { id: "new", label: "New campaign", icon: "sparkles", accent: true, href: "/campaign/new" },
  ];
  const camps = [
    { id: "dashboard", label: "Acme Q2 outbound", icon: "target", count: counts.dashboard, href: "/dashboard" },
    { id: "designers", label: "Design leads · NYC", icon: "target", count: 84, href: "/dashboard" },
    { id: "ent-saas", label: "Enterprise SaaS", icon: "target", count: 42, href: "/dashboard" },
  ];
  const lower = [
    { id: "drafts", label: "Drafts", icon: "file", count: 3, href: "/dashboard" },
    { id: "archive", label: "Archive", icon: "folder", count: undefined, href: "/dashboard" },
    { id: "settings", label: "Settings", icon: "settings", count: undefined, href: "/settings" },
  ];

  return (
    <div className="sidebar">
      <div className="sb-brand">
        <div className="sb-brand-mark">O</div>
        <div>Outreach</div>
        <Icon name="chev_d" size={12} style={{ marginLeft: "auto", color: "var(--fg-3)" }} />
      </div>
      {items.map((it) => (
        <Link key={it.id} href={it.href} style={{ textDecoration: "none", color: "inherit" }}>
          <div className={`sb-item ${isActive(it.id, it.href) ? "active" : ""}`} style={it.accent ? { color: "var(--accent)" } : undefined}>
            <Icon name={it.icon} size={14} style={it.accent ? { color: "var(--accent)" } : undefined} className="sb-icon" />
            <span>{it.label}</span>
            <span style={{ marginLeft: "auto", fontSize: 10.5, color: "var(--fg-3)", fontFamily: "var(--font-mono)" }}>⌘N</span>
          </div>
